Implementasi Observer Pattern yang robust untuk lingkungan produksi. Saya menyertakan *thread safety* menggunakan `threading.Lock` dan penanganan *exception* agar kegagalan satu observer tidak menjatuhkan seluruh sistem (mencegah DoS internal).

```python
from abc import ABC, abstractmethod
from typing import List, Any
import threading
import logging

# Konfigurasi Logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger("ShiroAI_Observer")

class Observer(ABC):
    @abstractmethod
    def update(self, subject: 'Subject') -> None:
        pass

class Subject(ABC):
    @abstractmethod
    def attach(self, observer: Observer) -> None:
        pass

    @abstractmethod
    def detach(self, observer: Observer) -> None:
        pass

    @abstractmethod
    def notify(self) -> None:
        pass

class ConcreteSubject(Subject):
    def __init__(self):
        self._observers: List[Observer] = []
        self._lock = threading.Lock()
        self._state: Any = None

    def attach(self, observer: Observer) -> None:
        with self._lock:
            if observer not in self._observers:
                self._observers.append(observer)
                logger.info(f"Observer attached: {observer}")

    def detach(self, observer: Observer) -> None:
        with self._lock:
            if observer in self._observers:
                self._observers.remove(observer)
                logger.info(f"Observer detached: {observer}")

    def set_state(self, state: Any) -> None:
        self._state = state
        self.notify()

    def notify(self) -> None:
        # Snapshot list untuk menghindari race condition saat iterasi
        with self._lock:
            observers_snapshot = list(self._observers)

        for observer in observers_snapshot:
            try:
                observer.update(self)
            except Exception as e:
                # Critical: Jangan biarkan error observer menghentikan notifikasi ke observer lain
                logger.error(f"Observer failed: {observer}. Error: {e}")

    def get_state(self) -> Any:
        return self._state

class ConcreteObserver(Observer):
    def __init__(self, name: str):
        self.name = name

    def update(self, subject: Subject) -> None:
        # Validasi data sebelum diproses (Prinsip Keamanan)
        state = subject.get_state()
        if not isinstance(state, (str, int, float, dict)):
            logger.warning(f"Observer {self.name} received unsafe data type")
            return

        logger.info(f"Observer {self.name} received state: {state}")

# Contoh Penggunaan
if __name__ == "__main__":
    subject = ConcreteSubject()
    obs1 = ConcreteObserver("SecurityMonitor")
    obs2 = ConcreteObserver("LogAnalyzer")

    subject.attach(obs1)
    subject.attach(obs2)

    subject.set_state({"alert": "SQL Injection Detected", "level": "CRITICAL"})

    subject.detach(obs1)
    subject.set_state("System Normal")
```

### Catatan Teknis & Keamanan:

1.  **Thread Safety:** Menggunakan `threading.Lock` pada operasi list `_observers`. Wajib untuk aplikasi multi-threaded (seperti server web) untuk mencegah *race condition*.
2.  **Exception Isolation:** Blok `try-except` di dalam `notify` memastikan jika satu observer crash (misalnya karena bug atau input malicious), observer lain tetap menerima notifikasi. Ini mencegah *Single Point of Failure*.
3.  **Validasi Data:** Pada `ConcreteObserver.update`, lakukan validasi tipe data `state`. Jangan pernah mempercayai data yang datang dari `Subject` tanpa sanitasi, terutama jika data tersebut akan dieksekusi atau ditampilkan (mencegah XSS/Injection jika data berasal dari input user).
4.  **Memory Leak:** Pastikan observer yang tidak lagi digunakan di-`detach` untuk mencegah referensi menggantung yang menghambat *Garbage Collection*.
